      <Routes>
        {/* 2. Set the path for the Login component */}
        <Route path="/" element={<Login />} />
        <Route path="/login" element={<Login />} />

        {/* Add other routes here */}
        {/* <Route path="/dashboard" element={<Dashboard />} /> */}
      </Routes>
    </BrowserRouter>
  );
}

export default App;
